// d3.js vendor placeholder.
//
// STUB. The real bundle (d3 v7, ~280 KB) exposes window.d3 with the full
// selection / scale / shape API. A faithful stub is impossible; this
// placeholder exposes window.d3 as a Proxy that returns no-op chainable
// stubs so a user/LLM-authored d3 snippet does not throw outright, plus a
// console.warn. Replace with the upstream bundle (see README.md).

(function () {
  if (typeof window === 'undefined') return;
  if (window.__topoD3Placeholder) return;
  window.__topoD3Placeholder = true;
  if (typeof console !== 'undefined' && console.warn) {
    console.warn(
      '[topo-debug] d3.min.js is a placeholder. Drop the real d3 bundle ' +
      'at topo-core/lib/Debug/Server/vendor/d3.min.js to enable custom ' +
      'd3 visualisations. See README.md in the same directory.'
    );
  }
  var noop = function () { return chainable; };
  var chainable = new Proxy(function () { return chainable; }, {
    get: function () { return noop; },
    apply: function () { return chainable; }
  });
  window.d3 = chainable;
})();
